<template><section v-if="errors.length" ref="root" class="sc-alert sc-alert-danger" role="alert" tabindex="-1" :aria-labelledby="titleId" data-form-error-summary><h2 :id="titleId">{{ title }}</h2><ul><li v-for="(error,index) in errors" :key="`${index}-${error}`"><button type="button" @click="$emit('select',error)">{{ error }}</button></li></ul><slot /></section></template>
<script setup lang="ts">import { ref,useId } from 'vue'; withDefaults(defineProps<{ errors:string[]; title?:string }>(),{title:'请检查以下内容'}); defineEmits<{select:[error:string]}>(); const root=ref<HTMLElement|null>(null); const titleId=`sc-error-summary-${useId()}`; defineExpose({focus:()=>root.value?.focus()});</script>
<style scoped>.sc-alert{display:grid;gap:var(--sc-product-space-2)}.sc-alert h2,.sc-alert ul{margin:0}.sc-alert h2{font-size:var(--sc-product-text-section)}.sc-alert button{border:0;padding:0;background:transparent;color:inherit;text-decoration:underline;cursor:pointer}</style>
